// Script Continued Below
var CustomTaskerFieldHelper = Class.create();
CustomTaskerFieldHelper.prototype = {
    initialize: function() {
    },

 	// RETURN - --------------------------------------------------------------------- 
 	// JSON object with custom additional fields added, some of the fields included in the Template instance already are:
 	// templateName, classification, templateNotation, shortDescription, u_template_subtask_s_name_setting, u_subtask_s_name_modifier, tableName,
	// tableSysID, assignedMember, objective, primaryAssignee, primaryOffice, restrictedGroup, taskingAuthority, u_external_ou, poc_name, outbound
	// u_internal_contact, u_internal_contact_performing_task, u_reviewer, u_on_behalf_of
	//
	// The object provided has all of the base fields in it.
	// To clear any of these fields, set the value and display value to blank.
	// Add your fields in this format:
	//    field_name: {value: '', displayValue:''}
	// or, if type that has no display value:
	//    field_name: {value: ''}
	addCustomFieldsToTemplateFieldsJSON: function(fields) {
		// examples...
		//	to add a new field called u_project as a reference field you would have a single line in this file
		//	  fields.u_project = {u_project: {value:'', displayValue:''}};
		//  to add a new field called u_project_type as a choice list you would have a single line in this file
		//	  fields.u_project_type = {u_project_type: {value:''}};
		return fields;
	},

	// NOTE: 2.7 - This is still used for OnChange of Template in the Platform pages to relod the information.
	//           - Customers need to implement this to have default values loaded from the Template to the Template instance when the template changes
	//           - This is ONLY used on the template run from task, not the template run
	// returns fields object with the additional information loaded from the template and task
	// This method is called when a Template is run from a Task
	// The method it is called from form load and loads a combination of Template and Task information
	// To see the fields loaded, see: 
	//   TaskTemplateHelpers().loadTemplateAndTaskIntoInstanceForm()
	//   This method is called after all of the field infrormation has been loaded
	//   This allows customers to modify any of the data being passed into the Template Instance on load
	loadCustomFieldsFromTemplateAndTaskIntoInstanceForm: function(fields, grTemplate, grTask) {
		// examples...
		//	To add data from the task object as a default value to a new field in the Template instance into a new field called u_project as a reference
		//  field you would have a single line in this file
		//	  fields.u_project.value = grTask.u_project;
		//	  fields.u_project.displayValue = grTask.getDisplayValue('u_project');
		//  To add data from the task object as a default value to a new field in the Template instance into a new field called  u_project_type as a
		//  choice list you would have a single line in this file
		//	 fields.u_project_type.value = grTask.u_project_type;

		//	To add data from the template object as a default value to a new field in the Template instance into a new field 
		//     called u_project as a reference field you would have a single line in this file
		//	  fields.u_project.value = grTemplate.u_project;
		//	  fields.u_project.displayValue = grTemplate.getDisplayValue('u_project');
		//  To add data from the task object as a default value to a new field in the Template instance into a new field called  u_project_type as a
		//  choice list you would have a single line in this file
		//	 fields.u_project_type.value = grTemplate.u_project_type;

		return fields;
	},

	// NOTE: 2.7 - This is still used for OnChange of Template in the Platform pages to relod the information.
	//           - Customers need to implement this to have default values loaded from the Template to the Template instance when the template changes
	//           - This is ONLY used on the template run, not the template run from task
	// returns fields object with the additional information loaded from the template
	// This method is called when a Template is run to start a new task tree
	// The method it is called from form load and loads Template information
	// To see the fields loaded, see: 
	//   TaskTemplateHelpers().loadTemplateIntoInstanceForm()
	//   This method is called after all of the field infrormation has been loaded
	//   This allows customers to modify any of the data being passed into the Template Instance on load
	loadCustomFieldsFromTemplateIntoInstanceForm: function(fields, grTemplate) {
		// examples...
		//	To add data from the template object as a default value to a new field in the Template instance into a new field 
		//     called u_project as a reference field you would have a single line in this file
		//	  fields.u_project.value = grTemplate.u_project;
		//	  fields.u_project.displayValue = grTemplate.getDisplayValue('u_project');
		//  To add data from the task object as a default value to a new field in the Template instance into a new field called  u_project_type as a
		//  choice list you would have a single line in this file
		//	 fields.u_project_type.value = grTemplate.u_project_type;
		return fields;
	},

	// returns the template instance object loaded with default values from the Template record
	// This method is called when a Template is run to load the default values form the Template into a template instance JSON object
	// To see the fields loaded, see: 
	//   TaskTemplateHelpers().loadInputDefaultFromTemplate()
	loadCustomFieldsInputDefaultFromTemplate : function(templateDefaults, template) {
		// examples...
		//	To load new custom default fields form the Template into the Template instance JSON object when Template run from schedule
		//     called u_project as a reference field you would have a single line in this file
		//	  templateDefaults.u_project = template.getValue('u_project');
		//  To add data from the task object as a default value to a new field in the Template instance into a new field called  u_project_type as a
		//  choice list you would have a single line in this file
		//	 templateDefaults.u_project_type = template.getValue('u_project_type');
		return templateDefaults;
	},

	// returns the template instance object loaded with all of the fields from the form or the event.
	// This method is called to create the Template Instance
	// To see the fields loaded, see: 
	//   TaskTemplateHelpers().createTemplateInstanceToRunTemplate()
	loadCustomInputsIntoTemplateInstanceObjectToRunTemplate : function(template, templateInstance, inputs) {
		// Examples
		// if inputs not populated in the method call, but you want to load the template default use this code:
		//if((inputs.u_project == undefined)  && template.getValue('u_project') != ''){
		//	inputs.u_project = template.getValue('u_project');
		//}
		// Load the input field into the runtime object
		//templateInstance.u_project = inputs.u_project;
		return templateInstance;
	},

	// This methods receives a copyAction, a from glide record grFrom, and to glide record, grTo
	// This method returns the to glide record, grTo, with the additional mapped fields form the from glide record, grFrom that mapped by the customer
	// This method is called from multiple places defined by the Action and documented in the outline
	mapFieldDataOnAction : function(copyAction, grFrom, grTo) {
		// To map a field for a specific actions use the copyAction switch and map the field.
		// It is not recommended to use the switch default b/c this method can be called more than once from the same Business rule.
		// For example, when a Template is run, the method is called to map:
		// - Template Information
		// - Template Instance Information
		// - and Template Task Information 
		// if inputs not populated in the method call, but you want to load the template default use this code:
		//if((inputs.u_project == undefined)  && template.getValue('u_project') != ''){
		//	inputs.u_project = template.getValue('u_project');
		//}
		// Load the input field into the runtime object
		//templateInstance.u_project = inputs.u_project;

		// to copy a field's data form grFrom to grTo for  a project reference, as an example
		// go to each method the data needs to be copied and add
		//   grTo.u_project = grFrom.u_project;
		// OR
		//   grTo.setValue('u_project', grFrom.getValue('u_project');

		switch(copyAction){
			case 'suggestedTasktoTask':
				// called from UI Action - Create Suggested Task
				// grFrom - x_153465_discovert_suggested_taskers
				// grTo - x_153465_discovert_route_task_instance
				break;
			case 'TemplateInstanceOnLoadDeaultFromTemplate':
				// called from Business Rule - Template Instance - Load Data
				//	 condition - always called as template is always provided to instance
				// grFrom - x_153465_discovert_discover_routing_template
				// grTo - x_153465_discovert_discover_routing_runtime
				// Example useage below, if the customer would like to have the suffix on the template loaded into the Template Instance form on load, uncomment these lines
				//var taskNameMod = grFrom.u_template_subtask_s_name_setting;
				//if(taskNameMod == 'prefix'){
				//	grTo.short_description = grFrom.u_subtask_s_name_modifier + ' - ' +  grTo.short_description;
				//} else if(taskNameMod == 'suffix'){
				//	grTo.short_description = grTo.short_description + ' - ' +  grFrom.u_subtask_s_name_modifier;
				//}

				break;				

			case 'TemplateInstanceOnLoadDeaultFromTask':
				// called from Business Rule - Template Instance - Load Data
				//	 condition - called only when template is run from a task
				// grFrom - x_153465_discovert_route_task_instance
				// grTo - x_153465_discovert_discover_routing_runtime
				// Example useage below, if the customer would like to have the suffix on the task loaded into the Template Instance form on load, uncomment these lines
				//var taskNameMod = grFrom.u_template_subtask_s_name_setting;
				//if(taskNameMod == 'prefix'){
				//	grTo.short_description = grFrom.u_subtask_s_name_modifier + ' - ' +  grTo.short_description;
				//} else if(taskNameMod == 'suffix'){
				//	grTo.short_description = grTo.short_description + ' - ' +  grFrom.u_subtask_s_name_modifier;
				//}

				break;
			case 'TemplateInstanceOnInsertScheduleTasksRun':				
				// called from Business Rule - Template Instance - On Insert -Scheduled
				//	 condition - called only when template is run from a scheudle
				// grFrom - x_153465_discovert_route_tasks
				// grTo - x_153465_discovert_discover_routing_runtime
				// Example useage below, if the customer would like to have the custom field my_new_field on the template loaded into the Template Instance when the schedule is run, it would look like this
				//	grTo.my_new_field = grFrom.my_new_field;

				break;
			case 'runTemplateTemplateInstanceToTopTask':
				// called from Business Rule - Task - onInsert Copy Template Task
				//	 condition - only when top task
				// grFrom - x_153465_discovert_discover_routing_runtime
				// grTo - x_153465_discovert_route_task_instance

				// Example useage below, if the customer would like to have the suffix entered applied to the top task also, uncomment these lines
				//var taskNameMod = grFrom.routing_template_ref.u_template_subtask_s_name_setting;
				//if(taskNameMod == 'prefix'){
				//	grTo.short_description = grFrom.u_subtask_s_name_modifier + ' - ' +  grTo.short_description;
				//} else if(taskNameMod == 'suffix'){
				//	grTo.short_description = grTo.short_description + ' - ' +  grFrom.u_subtask_s_name_modifier;
				//}

				break;
			case 'runTemplateTemplateInstanceToSubTask':
				// called from Business Rule - Task - onInsert Copy Template Task
				//	 condition - whenever NOT top task
				// grFrom - x_153465_discovert_discover_routing_runtime
				// grTo - x_153465_discovert_route_task_instance
				break;
			case 'runTemplateTemplateTaskToTopTask':
				// called from Business Rule - Task - onInsert Copy Template Task
				//	 condition - only when top task
				// grFrom - x_153465_discovert_route_tasks
				// grTo - x_153465_discovert_route_task_instance
				break;
			case 'runTemplateTemplateTaskToSubTask':
				// called from Business Rule - Task - onInsert Copy Template Task
				//	 condition - only when top task
				// grFrom - x_153465_discovert_route_tasks
				// grTo - x_153465_discovert_route_task_instance
				break;
			case 'taskOnDisplayNewChildTask':
				// called from Business Rule - Tasker - onDisplay - SubTask Create Copy
				// grFrom - x_153465_discovert_route_task_instance
				// grTo - x_153465_discovert_route_task_instance
				break;
			case 'templateCreateFromTaskSaveCopyFromTopTask':
				// called from Business Rule - Template - onInsert - newTopTask Save
				// grFrom - x_153465_discovert_route_task_instance
				// grTo - x_153465_discovert_discover_routing_template
				break;
			case 'templateCreateAddTopTaskTemplate':
				// called from Business Rule - Template - onInsert - newTopTask Save
				// grFrom - x_153465_discovert_discover_routing_template
				// grTo - x_153465_discovert_route_tasks
				break;

			// REMOVED from this function and now done in this function
			//case 'templateSyncTopTemplateTask':

				// mapFieldTemplateTaskTemplateDataOnAction
				// called from Business Rule - Template - onUpdate - Sync Top TempTask 
				// grFrom - x_153465_discovert_discover_routing_template
				// grTo - x_153465_discovert_route_tasks
			//	break;
			case 'templateTaskSaveAsTemplateCopyFromTask':
				// called from Business Rule - TemplateTask - onInsert - CopyInstance
				// grFrom - x_153465_discovert_route_task_instance
				// grTo - x_153465_discovert_route_tasks
				break;
			case 'templateTaskOnDisplayNewChildTemplateTask':
				// called from Business Rule - TemplTask - onDisplay - Copy New
				// grFrom - x_153465_discovert_route_tasks
				// grTo - x_153465_discovert_route_tasks
				break;
			// REMOVED from this function and now done in this function
			//case 'templateTaskSyncTemplate':
				// called from Business Rule - TemplTask - onDisplay - Copy New
				// grFrom - x_153465_discovert_route_tasks
				// grTo - x_153465_discovert_discover_routing_template
			//	break;
			case 'default':
				// all of the other items above could be commented out and thismethod will copy the field for every case called.
				// this is not recommended as the last call from each place where multiple things happen will win for setting grTo
				// This will typically have the biggest effect on forcing data from Template Task instead of Template
				break;
		}
		return grTo;
	},

	// This method is a copy of mapFieldDataOnAction desiged for Template Task and Task
	// The updates for Template to Template Task and Template TAsk to Template have been removed from the mapFieldDataOnAction function
	// This methods receives copyAction, a from glide record grFrom, and to glide record, grTo
	// This method returns the to glide record, grTo, with the additional mapped fields form the from glide record, grFrom that mapped by the customer
	// This method is called from multiple places defined by the Action and documented in the outline
	mapFieldTemplateTaskTemplateDataOnAction : function(copyAction, grFrom, grTo) {
		// To map a field for a specific actions use the copyAction switch and map the field.
		// It is not recommended to use the switch default b/c this method can be called more than once from the same Business rule.
		// For example, when a Template is run, the method is called to map:
		// - Template Information
		// - and Template Task Information 
		// if inputs not populated in the method call, but you want to load the template default use this code:
		//if((inputs.u_project == undefined)  && template.getValue('u_project') != ''){
		//	inputs.u_project = template.getValue('u_project');
		//}
		// Load the input field into the runtime object
		//templateInstance.u_project = inputs.u_project;

		// to copy a field's data form grFrom to grTo for  a project reference, as an example
		// go to each method the data needs to be copied and add
		//   grTo.u_project = grFrom.u_project;
		// OR
		//   grTo.setValue('u_project', grFrom.getValue('u_project');

		var fieldMapObject = {changed:false, grTo:grTo};
		switch(copyAction){
			case 'templateSyncTopTemplateTask':
				// called from Business Rule - Template - onUpdate - Sync Top TempTask 
				// grFrom - x_153465_discovert_discover_routing_template
				// grTo - x_153465_discovert_route_tasks
				// If value changed, then set fieldMapObject.changed = true;
				break;
			case 'templateTaskSyncTemplate':
				// called from Business Rule - TemplTask - onDisplay - Copy New
				// grFrom - x_153465_discovert_route_tasks
				// grTo - x_153465_discovert_discover_routing_template
				// If value changed, then set fieldMapObject.changed = true;
				break;
			case 'default':
				// all of the other items above could be commented out and thismethod will copy the field for every case called.
				// this is not recommended as the last call from each place where multiple things happen will win for setting grTo
				// This will typically have the biggest effect on forcing data from Template Task instead of Template
				break;
		}
		fieldMapObject.grTo = grTo;
		return fieldMapObject;
	},


    type: 'CustomTaskerFieldHelper'
	// ***********************************************************************************************
	// DEPCRECATED IN 2.7 - MOVING AWAY FROM WORKFLOW MADE THIS UNNECCESSARY
	// EVERYTHING BELOW HERE WAS DEPRECATED
	// ***********************************************************************************************
	// returns the template instance object with any additional information loaded from the template instance form fields
	// This method is called when a Template is run to start take teh data from the form and push it into a template JSON object
	// To see the fields loaded, see: 
	//   TaskTemplateHelpers().loadTemplateInputsFromDataFields()
	//   This method is called when the form is submitted 
	//   This allows customers to modify any of the data being passed into the Template Instance on submit
	//loadCustomFieldsItnoTemplateInputsFromDataFields : function(templateDefaults, fields) {
	//	// examples...
	//	//	To use data entered on the Template Instance form in the Template instance when started with a
	//	//     called u_project as a reference field you would have a single line in this file
	//	//	  templateDefaults.u_project = fields.u_project.value;
	//	//  To add data from the task object as a default value to a new field in the Template instance into a new field called  u_project_type as a
	//	//  choice list you would have a single line in this file
	//	//	 templateDefaults.u_project_type = fields.u_project_type.value;
	//	return templateDefaults;
	//},

};
